import React, { useEffect, useRef } from 'react';
import './Clients.css';

const CLIENTS = [
  { init: 'M', name: 'Magic Mind',        type: 'Health & Wellness Brand',  views: '↑ 450K views', bg: 'linear-gradient(135deg,#1a2a3a,#2a3a4a)' },
  { init: 'J', name: 'Juliano Spadafora', type: 'YouTube Creator · Finance', views: '↑ 1.2M views', bg: 'linear-gradient(135deg,#2a1a1a,#3a2020)' },
  { init: 'R', name: 'Rhys Roberts',      type: 'Lifestyle Creator',         views: '↑ 320K views', bg: 'linear-gradient(135deg,#1a2a1a,#253525)' },
  { init: 'S', name: 'Shreetabh Gangwar', type: 'Tech & Business',           views: '↑ 780K views', bg: 'linear-gradient(135deg,#1a1a2a,#20203a)' },
  { init: 'C', name: 'Curious Mind Co.',  type: 'Educational Channel',       views: '↑ 550K views', bg: 'linear-gradient(135deg,#2a1a2a,#3a2535)' },
  { init: 'N', name: 'NextGen Investing', type: 'Finance Channel',           views: '↑ 920K views', bg: 'linear-gradient(135deg,#2a2a1a,#383520)' },
];

export default function Clients() {
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) ref.current.querySelectorAll('.reveal').forEach(r => r.classList.add('visible'));
    }, { threshold: 0.1 });
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  return (
    <section className="section clients-section" id="clients" ref={ref}>
      <p className="sec-tag reveal">03 — Edited For</p>
      <h2 className="sec-title reveal">Creators &amp; Brands</h2>
      <div className="clients-grid reveal">
        {CLIENTS.map(c => (
          <div className="client-card" key={c.name}>
            <div className="cc-avatar" style={{ background: c.bg }}>{c.init}</div>
            <div>
              <div className="cc-name">{c.name}</div>
              <div className="cc-type">{c.type}</div>
            </div>
            <div className="cc-views">{c.views}</div>
          </div>
        ))}
      </div>
    </section>
  );
}
